// MARK: - Mock VenuesStore
class MockVenuesStore: VenuesStoreProtocol {
    // Configuration properties
    var getVenuesResult: Result<[Venue], Error> = .success([])
    var storedFavorites: Set<Venue.ID> = []
    var storedNotFavorites: Set<Venue.ID> = []

    // Spy properties
    var getVenuesCallCount = 0
    var lastRequestedLocation: LocationCoordinate2D?
    var storeFavoriteVenuesCallCount = 0

    func getVenues(for location: LocationCoordinate2D) async throws -> [Venue] {
        getVenuesCallCount += 1
        lastRequestedLocation = location

        switch getVenuesResult {
        case .success(let venues):
            return venues
        case .failure(let error):
            throw error
        }
    }

    func storeFavoriteVenues(_ favorites: Set<Venue.ID>, _ notFavorites: Set<Venue.ID>) {
        storeFavoriteVenuesCallCount += 1
        storedFavorites = favorites
        storedNotFavorites = notFavorites
    }
}

// MARK: - Mock LocationStore
class MockLocationStore: LocationStoreProtocol {
    // Configuration properties
    var locationSequence: [LocationCoordinate2D] = []
    private var locationContinuation: AsyncStream<LocationCoordinate2D>.Continuation?

    // Spy properties
    var locationEmissionCount = 0

    lazy var location: AsyncStream<LocationCoordinate2D> = {
        AsyncStream { continuation in
            self.locationContinuation = continuation
            // Emit initial values if any
            for location in locationSequence {
                continuation.yield(location)
                locationEmissionCount += 1
            }
        }
    }()

    // Helper method to emit new locations during tests
    func emitLocation(_ location: LocationCoordinate2D) {
        locationContinuation?.yield(location)
        locationEmissionCount += 1
    }

    func finish() {
        locationContinuation?.finish()
    }
}

// MARK: - Mock ImageCache
class MockImageCache: ImageCache {
    // Configuration properties
    var imageResult: Result<UIImage?, Error> = .success(nil)

    // Spy properties
    var loadImageCallCount = 0
    var lastRequestedURL: URL?
    var lastRequestedSize: CGSize?

    func thumbnailImage(for url: URL, size: CGSize) async -> UIImage? {
        loadImageCallCount += 1
        lastRequestedURL = url
        lastRequestedSize = size

        switch imageResult {
        case .success(let image):
            return image
        case .failure(let error):
            // In real implementation, we might want to handle errors differently
            // For now, just return nil on error as per protocol
            return nil
        }
    }
}

